def test_fires_and_writes_summary_end_to_end(
    session_dir: Path, shim_succeeds: tuple[Path, Path]
) -> None:
    shim_path, capture_path = shim_succeeds
    _write_explore(session_dir, _high_signal_explore())
    result = _run(session_dir, pythonpath=shim_path)
    assert result.returncode == 0, f"stderr: {result.stderr}"
    assert "signal fired" in result.stdout
    assert "wrote" in result.stdout

    md_path = session_dir / "explore-summary.md"
    assert md_path.exists()
    assert "Explore summary" in md_path.read_text(encoding="utf-8")

    handoff = _load_handoff(session_dir)
    assert handoff["status"] == "fired"
    assert handoff["notebook_id"] == "nb-test-12345"
    assert handoff["summary_path"] == str(md_path)
    assert handoff["size_bytes"] > 0

    # Verify the MCP call payload was the right shape.
    assert capture_path.exists(), "shim did not capture the call"
    captured = json.loads(capture_path.read_text(encoding="utf-8"))
    assert captured["tool"] == "notebook_query"
    assert captured["args"]["notebook_id"] == "nb-test-12345"
    assert captured["args"]["query"].startswith("Summarize this exploration session:")


